renderAttendanceReport=function(start){const history=data.histories.find(h=>h.workId===activeId&&h.type==="attendance"&&h.weekStart===start),snap=history?.snapshot||attendanceSnapshotFor(activeId,start),work=snap.work,days=snap.days,staff=snap.workers,vs=snap.visitors,groups=new Map();staff.forEach(w=>{const key=w.contractorName||"Sin contratista";if(!groups.has(key))groups.set(key,[]);groups.get(key).push(w);});const sections=[...groups].map(([company,list])=>`<div class="attendance-contractor">${esc(company)} · ${list.length} trabajadores</div><table class="report-table"><thead><tr><th>No.</th><th>Nombre</th><th>Puesto</th><th>NSS</th><th>Ingreso</th><th>Nuevo</th><th>Destajista</th><th>Taller</th>${days.map(d=>`<th>${new Date(d+"T12:00").toLocaleDateString("es-MX",{weekday:"short"})}<br>${d.slice(5)}</th>`).join("")}<th>Total</th></tr></thead><tbody>${list.map((w,i)=>{const marks=days.map(d=>snap.attendance[d]?.[w.id]||"-");return `<tr><td>${i+1}</td><td>${esc(w.name)}</td><td>${esc(w.position)}</td><td>${esc(w.nss)}</td><td>${fmt(w.admissionDate)}</td><td>${esc(w.newEntry||"No")}</td><td>${esc(w.pieceworker||"No")}</td><td>${esc(w.workshop||"No")}</td>${marks.map(v=>`<td>${esc(v)}</td>`).join("")}<td>${marks.filter(v=>v==="P").length}</td></tr>`;}).join("")}</tbody></table>`).join("");const html=`<article class="week-report"><div class="week-title"><b>GRAN VISIÓN CONSTRUCCIÓN · Rev. 02</b><h1>LISTA DE ASISTENCIA SEMANAL</h1><p>${esc(work.development)} · ${esc(work.name)} · ${fmt(start)} al ${fmt(days[6])}</p></div><div class="official-meta"><div><b>ELABORÓ</b>${esc(work.preparedBy||"Sin asignar")}</div><div><b>LUGAR</b>${esc(work.location)}</div><div><b>OBRA / CENTRO DE COSTO</b>${esc(work.name)} / ${esc(work.costCenter||"-")}</div><div><b>OT / FRENTE / PARTIDA</b>${esc(work.workOrder||"-")} / ${esc(work.front||"-")} / ${esc(work.partida||"-")}</div></div>${sections||'<div class="report-notes">Sin trabajadores registrados.</div>'}<div class="report-band">Visitantes de la semana</div><table class="report-table"><thead><tr><th>Nombre</th><th>Empresa</th><th>Fecha</th><th>Entrada</th><th>Salida</th><th>Motivo / Persona visitada</th></tr></thead><tbody>${vs.map(v=>`<tr><td>${esc(v.name)}</td><td>${esc(v.company)}</td><td>${fmt(v.date)}</td><td>${esc(v.entry)}</td><td>${esc(v.exit||"-")}</td><td>${esc(v.reason)} · ${esc(v.visits)}</td></tr>`).join("")||'<tr><td colspan="6">Sin visitantes</td></tr>'}</tbody></table></article>`;baseOpenSystemReport(html,{type:"attendance",downloadName:"asistencia-semanal",date:days[6],weekStart:start,workId:activeId,code:"GVC-CON-REG-036-F11",revision:"Rev. 02",work});};

function augmentPhase2Investigation(form){if(!form||form.dataset.officialComplete)return;form.dataset.officialComplete="1";form.querySelector(".investigation-sections")?.insertAdjacentHTML("beforeend",'<div class="wide classification-grid"><label>Fecha de nacimiento<input name="workerBirthDate" type="date"></label><label>Sexo<select name="workerSex"><option value="">No especificado</option><option>Femenino</option><option>Masculino</option><option>Otro</option></select></label><label>Domicilio del trabajador<input name="workerAddress"></label><label>Antigüedad en la ocupación<input name="occupationTime"></label><label>Turno habitual<select name="usualShift"><option>Diurno</option><option>Nocturno</option><option>Mixto</option><option>Por turnos</option></select></label><label>Día del accidente<input name="accidentWeekday" readonly></label></div>');q("#investigationWorker")?.addEventListener("change",e=>{const w=data.workers.find(x=>x.id===e.target.value);if(!w)return;form.elements.workerBirthDate.value=w.birthDate||"";form.elements.workerSex.value=w.sex||"";form.elements.workerAddress.value=w.address||"";form.elements.occupationTime.value=w.occupationTime||"";});form.elements.date?.addEventListener("change",()=>{form.elements.accidentWeekday.value=form.elements.date.value?new Date(form.elements.date.value+"T12:00").toLocaleDateString("es-MX",{weekday:"long"}):"";});if(form.elements.date)form.elements.date.dispatchEvent(new Event("change"));form.addEventListener("submit",e=>{const f=new FormData(e.currentTarget),x=data.investigations[data.investigations.length-1];if(!x||x.workId!==activeId)return;Object.assign(x,{workerBirthDate:f.get("workerBirthDate"),workerSex:f.get("workerSex"),workerAddress:f.get("workerAddress"),occupationTime:f.get("occupationTime"),usualShift:f.get("usualShift"),accidentWeekday:f.get("accidentWeekday")});save();renderInvestigationReport(x);});}
