function documentsAcrossWorks(){return data.works.flatMap(work=>allDocuments(work.id).map(doc=>({...doc,workId:work.id,workName:work.name,development:work.development})));}
function documentDate(doc){return doc.date||doc.weekStart||doc.createdAt?.slice(0,10)||"";}
function documentFolio(doc){if(doc.folio)return doc.folio;if(doc.type==="investigation")return data.investigations.find(x=>x.id===doc.investigationId)?.folio||"";if(doc.type==="attendance")return `SEM-${doc.weekStart||documentDate(doc)}`;return doc.documentNumber||"";}
function documentContractor(doc){if(doc.type==="investigation")return data.investigations.find(x=>x.id===doc.investigationId)?.contractor||"";if(doc.type==="attendance")return [...new Set((doc.snapshot?.workers||[]).map(w=>w.contractorName).filter(Boolean))].join(", ");return doc.contractor||doc.fields?.contractor||"";}
function openFilteredDocument(doc){const previous=activeId;activeId=doc.workId;try{if(doc.type==="attendance")return renderAttendanceReport(doc.weekStart);if(doc.type==="investigation")return renderInvestigationReport(data.investigations.find(x=>x.id===doc.investigationId));currentRecord=doc;if(doc.type==="incident")renderIncidentReport(doc);else if(doc.type==="firstAid")renderFirstAidReport(doc);else if(equipmentConfigs[doc.type])renderEquipmentReport(doc);else renderReport(doc);showView("reportView");}finally{activeId=previous;}}
function historyFiltersMarkup(docs){const types=[...new Set(docs.map(d=>d.type||"otros"))].sort(),contractorNames=[...new Set([...data.contractors.map(c=>c.name),...docs.map(documentContractor)].filter(Boolean))].sort();return `<div class="history-filters"><label>Búsqueda rápida<input id="historySearch" type="search" placeholder="Folio, persona, obra o documento"></label><label>Obra<select id="historyWork"><option value="">Todas las obras</option>${data.works.map(w=>`<option value="${w.id}" ${w.id===activeId?"selected":""}>${esc(w.name)}</option>`).join("")}</select></label><label>Tipo de documento<select id="historyType"><option value="">Todos</option>${types.map(t=>`<option value="${esc(t)}">${esc(historyLabel(t))}</option>`).join("")}</select></label><label>Contratista<select id="historyContractor"><option value="">Todos</option>${contractorNames.map(name=>`<option>${esc(name)}</option>`).join("")}</select></label><label>Desde<input id="historyFrom" type="date"></label><label>Hasta<input id="historyTo" type="date"></label></div><div id="historyResults"></div>`;}
function bindHistoryFilters(docs){const render=()=>{const search=(q("#historySearch")?.value||"").toLowerCase(),work=q("#historyWork")?.value||"",type=q("#historyType")?.value||"",contractor=q("#historyContractor")?.value||"",from=q("#historyFrom")?.value||"",to=q("#historyTo")?.value||"";const filtered=docs.filter(d=>{const date=documentDate(d),contractorText=documentContractor(d),haystack=[documentFolio(d),d.weekStart,d.status,d.workName,d.development,historyLabel(d.type),contractorText,d.injuredName,d.description].filter(Boolean).join(" ").toLowerCase();return(!search||haystack.includes(search))&&(!work||d.workId===work)&&(!type||d.type===type)&&(!contractor||contractorText.includes(contractor))&&(!from||date>=from)&&(!to||date<=to);}).sort((a,b)=>documentDate(b).localeCompare(documentDate(a)));q("#historyResults").innerHTML=`<div class="history-results-head"><h2>Documentos</h2><span>${filtered.length} resultado${filtered.length===1?"":"s"}</span></div>${filtered.length?`<div class="history-list">${filtered.map((d,i)=>`<article class="history-item"><div><h3>${esc(historyLabel(d.type))}</h3><p>${fmt(documentDate(d))} · ${esc(documentFolio(d)||"Sin folio")}</p><div class="history-item-meta"><span class="history-tag">${esc(d.workName)}</span>${documentContractor(d)?`<span class="history-tag">${esc(documentContractor(d))}</span>`:""}</div></div><button class="secondary" data-filtered-doc="${i}">Abrir documento</button></article>`).join("")}</div>`:'<div class="empty-management">No hay documentos que coincidan con los filtros.</div>'}`;qa("[data-filtered-doc]").forEach(button=>button.onclick=()=>openFilteredDocument(filtered[Number(button.dataset.filteredDoc)]));};["#historySearch","#historyWork","#historyType","#historyContractor","#historyFrom","#historyTo"].forEach(selector=>q(selector)?.addEventListener(selector==="#historySearch"?"input":"change",render));render();}
renderHistories=function(){const docs=documentsAcrossWorks();q("#managementContent").innerHTML=historyFiltersMarkup(docs);bindHistoryFilters(docs);};

