function migratePhase3Data(){
  data.schemaVersion=Math.max(Number(data.schemaVersion)||1,5);data.compliance||={};data.activity||=[];data.complianceMatrix??={sourceCode:"GVC-SSH-MAT-001",mode:"summary-compatible",nomCount:13,criteriaCount:756,updatedAt:"2026-06-19"};
  data.works.forEach(work=>{work.workNumber??="";work.client??="";work.resident??="";work.sstResponsible??="";work.startDate??="";work.estimatedEndDate??="";work.status??="Activa";work.deletedAt??=null;ensureCompliance(work.id);});save();
}
function ensureCompliance(workId){data.compliance[workId]||={};nomDefinitions.forEach(([code,title])=>{const meta=nomMatrixMeta[code],entry=data.compliance[workId][code]||={code,title,status:"No aplica",responsible:"",reviewDate:"",observations:"",evidence:[],percentage:0,updatedAt:""};entry.title??=title;entry.officialCode??=meta.official;entry.criteriaTotal??=meta.criteria;entry.criteriaCompliant??=0;entry.criteriaNotApplicable??=0;entry.matrixAligned??=false;entry.evidence??=[];data.compliance[workId][code]=entry;});return nomDefinitions.map(([code])=>data.compliance[workId][code]);}
function complianceStats(workId){const entries=ensureCompliance(workId),applicable=entries.filter(x=>x.status!=="No aplica"),weighted=applicable.map(x=>({value:Number(x.percentage)||0,weight:x.matrixAligned?Math.max(1,(Number(x.criteriaTotal)||0)-(Number(x.criteriaNotApplicable)||0)):1})),weightTotal=weighted.reduce((sum,x)=>sum+x.weight,0),general=weightTotal?Math.round(weighted.reduce((sum,x)=>sum+x.value*x.weight,0)/weightTotal):0,risk=[...applicable].sort((a,b)=>(a.percentage||0)-(b.percentage||0))[0]||null,counts={"Cumple":0,"Parcial":0,"No cumple":0,"No aplica":0};entries.forEach(x=>counts[x.status]=(counts[x.status]||0)+1);return {entries,applicable,general,risk,pending:entries.filter(x=>x.status==="Parcial"||x.status==="No cumple").length,counts};}
function workById(id){return data.works.find(x=>x.id===id);}
