function bindExecutiveNavigation(){
  const close=()=>document.body.classList.remove("sidebar-open");q("#sidebarToggle").onclick=()=>document.body.classList.toggle("sidebar-open");q("#sidebarBackdrop").onclick=close;
  qa("[data-phase3-nav]").forEach(button=>button.onclick=()=>{const target=button.dataset.phase3Nav;close();markSidebar(target);if(target==="dashboard"){if(activeWork()){renderDashboard();displayView("homeView");}else{renderWorks();displayView("worksView");}}else if(target==="works"){renderWorks();displayView("worksView");}else if(["contractors","workers","visitors","attendance","workforce","investigations","histories"].includes(target))openModule(target);else if(target==="incidents")q("#incidentButton")?.click();else if(target==="inspections")q("#inspectionButton")?.click();else if(target==="badges")openModule("workers");else if(target==="compliance")openComplianceModule();else if(target==="matrix")openMatrixCompatibility();});
}
function markSidebar(target){qa("[data-phase3-nav]").forEach(x=>x.classList.toggle("active",x.dataset.phase3Nav===target));}

function prepareWorkForm(work=null){const form=q("#workForm");form.reset();form.dataset.editId=work?.id||"";q("#workForm .section-title h2").textContent=work?"Editar obra":"Nueva obra";if(work)Object.entries(work).forEach(([key,value])=>{if(form.elements[key])form.elements[key].value=value??"";});form.hidden=false;form.scrollIntoView({behavior:"smooth",block:"start"});}
function bindPhase3WorkForm(){const form=q("#workForm");q("#newWorkButton").onclick=()=>prepareWorkForm();form.onsubmit=e=>{e.preventDefault();const f=new FormData(form),existing=data.works.find(x=>x.id===form.dataset.editId),work=existing||{id:uid(),createdAt:new Date().toISOString(),deletedAt:null};Object.assign(work,{development:f.get("development"),name:f.get("name"),location:f.get("location"),details:f.get("details"),workNumber:f.get("workNumber")||"",client:f.get("client")||"",costCenter:f.get("costCenter")||"",workOrder:f.get("workOrder")||"",front:f.get("front")||"",partida:f.get("partida")||"",resident:f.get("resident")||"",sstResponsible:f.get("sstResponsible")||"",startDate:f.get("startDate")||"",estimatedEndDate:f.get("estimatedEndDate")||"",status:f.get("status")||"Activa",preparedBy:f.get("preparedBy")||"",superintendent:f.get("superintendent")||""});if(!existing)data.works.push(work);ensureCompliance(work.id);recordActivity("work",existing?`Obra actualizada: ${work.name}`:`Obra creada: ${work.name}`,work.id);save();form.hidden=true;renderWorks();};}
function workDataCount(id){const attendance=Object.keys(data.attendance).filter(k=>k.startsWith(id+"|")).length;return allDocuments(id).length+data.visitors.filter(x=>x.workId===id).length+data.investigations.filter(x=>x.workId===id).length+attendance;}
renderWorks=function(){const grid=q("#worksGrid"),allVisible=data.works.filter(w=>!w.deletedAt),hasReal=allVisible.some(w=>w.id!=="legacy"),visible=hasReal?allVisible.filter(w=>w.id!=="legacy"):allVisible,deleted=data.works.filter(w=>w.deletedAt&&w.id!=="legacy");grid.innerHTML=`${visible.map(work=>`<article class="work-card ${work.id==="legacy"?"legacy-work-card":""}"><div class="work-card-head"><p class="eyebrow">${esc(work.development)}</p><span class="work-status ${work.id==="legacy"?"inactive":work.status.toLowerCase()==="activa"?"active":work.status.toLowerCase()==="cerrada"?"closed":"inactive"}">${work.id==="legacy"?"HEREDADA":esc(work.status)}</span></div><h2>${esc(work.name)}</h2><p>${work.id==="legacy"?"Registros anteriores pendientes de asignar":`${esc(work.workNumber||"Sin número")} · ${esc(work.client||"Sin cliente")}`}</p><p>${esc(work.location)}</p><div class="work-card-stats"><span><b>${data.contractors.filter(x=>x.workId===work.id&&x.status==="Activo").length}</b>Contratistas activos</span><span><b>${presentCount(work.id,today())}</b>Presentes hoy</span></div><div class="work-card-actions"><button class="primary" data-select-work="${work.id}">Abrir</button>${work.id==="legacy"?"":`<button class="secondary" data-edit-work="${work.id}">Editar</button><button class="secondary" data-status-work="${work.id}">${work.status==="Activa"?"Desactivar":"Activar"}</button><button class="secondary" data-close-work="${work.id}">Cerrar</button><button class="ghost danger-action" data-delete-work="${work.id}">Eliminar</button>`}</div></article>`).join("")||'<div class="empty-management">No hay obras activas. Crea una para comenzar.</div>'}${deleted.length?`<section class="deleted-works"><h2>Obras eliminadas</h2>${deleted.map(work=>`<article class="work-card deleted"><div><span class="work-status deleted">Eliminada</span><h3>${esc(work.name)}</h3><p>${esc(work.location)}</p></div><button class="secondary" data-recover-work="${work.id}">Recuperar obra</button></article>`).join("")}</section>`:""}`;qa("[data-select-work]",grid).forEach(b=>b.onclick=()=>setActive(b.dataset.selectWork));qa("[data-edit-work]",grid).forEach(b=>b.onclick=()=>prepareWorkForm(workById(b.dataset.editWork)));qa("[data-status-work]",grid).forEach(b=>b.onclick=()=>{const w=workById(b.dataset.statusWork);w.status=w.status==="Activa"?"Inactiva":"Activa";recordActivity("work",`Estatus de obra: ${w.status}`,w.id);save();renderWorks();});qa("[data-close-work]",grid).forEach(b=>b.onclick=()=>{const w=workById(b.dataset.closeWork);if(confirm(`¿Cerrar la obra ${w.name}? Los datos seguirán disponibles.`)){w.status="Cerrada";recordActivity("work","Obra cerrada",w.id);save();renderWorks();}});qa("[data-delete-work]",grid).forEach(b=>b.onclick=()=>{const w=workById(b.dataset.deleteWork),count=workDataCount(w.id),warning=count?`La obra contiene ${count} registros relacionados. `:"";if(!confirm(`${warning}La eliminación será lógica y recuperable. ¿Continuar?`))return;if(!confirm(`Segunda confirmación: ¿marcar ${w.name} como eliminada?`))return;w.deletedAt=new Date().toISOString();w.status="Eliminada";recordActivity("work","Obra eliminada lógicamente",w.id);save();if(activeId===w.id){activeId="";localStorage.removeItem(ACTIVE_KEY);}renderWorks();});qa("[data-recover-work]",grid).forEach(b=>b.onclick=()=>{const w=workById(b.dataset.recoverWork);w.deletedAt=null;w.status="Inactiva";recordActivity("work","Obra recuperada",w.id);save();renderWorks();});};

function complianceClass(entry){return entry.status==="Cumple"?"":entry.status==="Parcial"?"partial":"risk";}
function openComplianceModule(){q("#managementTitle").textContent="Cumplimiento normativo";q("#managementSubtitle").textContent="Evaluación por NOM de la obra activa";q("#managementActions").innerHTML='<button class="secondary" id="compliancePdf">Generar reporte</button>';q("#compliancePdf").onclick=()=>createComplianceDocument();renderComplianceModule();displayView("managementView");markSidebar("compliance");}
function openMatrixCompatibility(){const stats=complianceStats(activeId),total=Object.values(nomMatrixMeta).reduce((sum,x)=>sum+x.criteria,0);q("#managementTitle").textContent="Matriz de cumplimiento";q("#managementSubtitle").textContent="Compatibilidad con GVC-SSH-MAT-001";q("#managementActions").innerHTML='<button class="primary" id="openComplianceFromMatrix">Evaluar cumplimiento</button>';q("#managementContent").innerHTML=`<section class="matrix-reference-hero"><div><span>REFERENCIA PRINCIPAL GRAVI</span><h2>GVC-SSH-MAT-001</h2><p>La aplicación conserva un resumen operativo compatible con los pares <b>Cumple / N/A</b> de la matriz oficial, sin duplicar sus 939 filas.</p></div><div class="matrix-reference-kpis"><b>13<small>NOM</small></b><b>${total}<small>criterios</small></b><b>${stats.general}%<small>obra actual</small></b></div></section><div class="matrix-method"><h2>Regla de cálculo compatible</h2><p><b>Pendiente o no cumple</b> = criterio sin marcar en Cumple ni N/A. El porcentaje se calcula sobre criterios aplicables: Cumple ÷ (Total − N/A). El indicador general se pondera por el número de criterios aplicables.</p></div><div class="matrix-reference-grid">${nomDefinitions.map(([code,title])=>{const meta=nomMatrixMeta[code],entry=stats.entries.find(x=>x.code===code);return `<article class="matrix-reference-card"><div><b>${meta.official}</b><span class="nom-status">${esc(entry.status)}</span></div><p>${esc(title)}</p><small>${meta.sections} apartados · ${meta.criteria} criterios · ${entry.matrixAligned?"Alineada":"Pendiente de captura compatible"}</small></article>`;}).join("")}</div>`;q("#openComplianceFromMatrix").onclick=openComplianceModule;displayView("managementView");markSidebar("matrix");}
function renderComplianceModule(editCode=""){const stats=complianceStats(activeId),entry=stats.entries.find(x=>x.code===editCode);q("#managementContent").innerHTML=`${entry?complianceForm(entry):""}<div class="compliance-overview"><div class="compliance-score-card"><span>CUMPLIMIENTO GENERAL</span><strong>${stats.general}%</strong><span>${stats.applicable.length} NOM aplicables · ${stats.pending} con pendientes</span></div><div class="nom-management-grid">${stats.entries.map(x=>`<article class="nom-card"><div class="nom-card-head"><h3>${x.code}</h3><span class="nom-status">${esc(x.status)}</span></div><p>${esc(x.title)}</p><div class="nom-progress"><span class="${complianceClass(x)}" style="width:${Number(x.percentage)||0}%"></span></div><small>${Number(x.percentage)||0}% · ${esc(x.responsible||"Sin responsable")}</small><div class="compliance-evidence">${(x.evidence||[]).slice(0,3).map(src=>`<img src="${src}" alt="Evidencia">`).join("")}</div><button class="secondary" data-edit-nom="${x.code}">Actualizar</button></article>`).join("")}</div></div>`;qa("[data-edit-nom]").forEach(b=>b.onclick=()=>renderComplianceModule(b.dataset.editNom));q("#complianceForm")?.addEventListener("submit",saveComplianceEntry);}
function complianceForm(entry){const total=Number(entry.criteriaTotal)||nomMatrixMeta[entry.code].criteria,compliant=entry.matrixAligned?Number(entry.criteriaCompliant)||0:entry.status==="No aplica"?0:Math.round(total*(Number(entry.percentage)||0)/100),notApplicable=entry.matrixAligned?Number(entry.criteriaNotApplicable)||0:entry.status==="No aplica"?total:0;return `<form id="complianceForm" class="modal-form"><div class="section-title"><span>NOM</span><div><h2>${entry.officialCode||entry.code}</h2><p>${esc(entry.title)}</p></div></div><input type="hidden" name="code" value="${entry.code}"><div class="matrix-form-note"><b>Resumen compatible con GVC-SSH-MAT-001</b><span>Registra los totales de la matriz. Los criterios sin marcar como Cumple o N/A se consideran pendientes.</span></div><div class="field-grid matrix-count-grid"><label>Criterios de referencia<input name="criteriaTotal" type="number" min="1" value="${total}" readonly></label><label>Cumple<input name="criteriaCompliant" type="number" min="0" max="${total}" value="${compliant}" required></label><label>No aplica<input name="criteriaNotApplicable" type="number" min="0" max="${total}" value="${notApplicable}" required></label><label class="wide">Responsable<input name="responsible" value="${esc(entry.responsible)}" required></label><label>Fecha de revisión<input name="reviewDate" type="date" value="${entry.reviewDate||today()}" required></label><label class="wide">Observaciones<textarea name="observations" rows="3">${esc(entry.observations)}</textarea></label><label class="wide">Evidencias<input name="evidence" type="file" accept="image/*" multiple></label></div><div class="form-footer"><button class="ghost" id="cancelCompliance" type="button">Cancelar</button><button class="primary">Calcular y guardar</button></div></form>`;}
async function saveComplianceEntry(event){event.preventDefault();const f=new FormData(event.currentTarget),entry=ensureCompliance(activeId).find(x=>x.code===f.get("code")),total=Number(f.get("criteriaTotal"))||0,compliant=Number(f.get("criteriaCompliant"))||0,notApplicable=Number(f.get("criteriaNotApplicable"))||0;if(compliant+notApplicable>total){toast("Cumple y N/A no pueden superar el total de criterios.");return;}const applicable=total-notApplicable,percentage=applicable?Math.round(compliant/applicable*100):0,status=!applicable?"No aplica":percentage===100?"Cumple":percentage>0?"Parcial":"No cumple";Object.assign(entry,{status,percentage,criteriaTotal:total,criteriaCompliant:compliant,criteriaNotApplicable:notApplicable,matrixAligned:true,responsible:f.get("responsible"),reviewDate:f.get("reviewDate"),observations:f.get("observations"),updatedAt:new Date().toISOString()});const files=[...event.currentTarget.elements.evidence.files].slice(0,5);for(const file of files)entry.evidence.push(await resizeImage(file));entry.evidence=entry.evidence.slice(-8);recordActivity("compliance",`${entry.code} actualizado a ${entry.status}`);save();renderComplianceModule();toast(`Evaluación guardada: ${percentage}% de cumplimiento.`);}
function nextComplianceFolio(){const year=new Date().getFullYear(),count=data.histories.filter(x=>x.type==="compliance"&&(x.folio||"").startsWith(`CUM-${year}`)).length+1;return `CUM-${year}-${String(count).padStart(4,"0")}`;}
function createComplianceDocument(){const work={...activeWork()},stats=complianceStats(activeId),doc={id:uid(),workId:activeId,type:"compliance",date:today(),folio:nextComplianceFolio(),createdAt:localDateTimeISO(),complianceSnapshot:{work,entries:stats.entries.map(x=>({...x,evidence:[...(x.evidence||[])],criteria:(x.criteria||[]).map(item=>({...item,evidence:[...(item.evidence||[])]}))})),stats:{general:stats.general,pending:stats.pending}}};data.histories.push(doc);recordActivity("compliance",`Reporte normativo ${doc.folio} generado`);save();renderComplianceReport(doc);}
function renderComplianceReport(doc){const snapshot=doc.complianceSnapshot||{work:workById(doc.workId),entries:ensureCompliance(doc.workId),stats:complianceStats(doc.workId)},entries=snapshot.entries,html=`<div class="report-title"><div class="report-logo">GVC</div><div><b>GRAN VISIÓN CONSTRUCCIÓN</b><h1>REPORTE DE CUMPLIMIENTO NORMATIVO</h1></div><div><b>${esc(doc.folio||"BORRADOR")}</b><br>Rev. 01</div></div><div class="official-meta"><div><b>OBRA</b>${esc(snapshot.work?.name)}</div><div><b>UBICACIÓN</b>${esc(snapshot.work?.location)}</div><div><b>RESPONSABLE SST</b>${esc(snapshot.work?.sstResponsible||"-")}</div><div><b>CUMPLIMIENTO GENERAL</b>${snapshot.stats.general}%</div></div><div class="report-band">Evaluación por NOM · Referencia GVC-SSH-MAT-001</div><table class="report-table compliance-report-table"><thead><tr><th>NOM</th><th>Estado</th><th>%</th><th>Criterios C / N.A. / P</th><th>Responsable</th><th>Revisión</th><th>Observaciones</th></tr></thead><tbody>${entries.map(x=>{const total=Number(x.criteriaTotal)||nomMatrixMeta[x.code]?.criteria||0,compliant=Number(x.criteriaCompliant)||0,na=Number(x.criteriaNotApplicable)||0,pending=Math.max(0,total-compliant-na);return `<tr><td>${esc(x.officialCode||x.code)}</td><td>${esc(x.status)}</td><td>${Number(x.percentage)||0}%</td><td>${x.matrixAligned?`${compliant} / ${na} / ${pending}`:"Resumen anterior"}</td><td>${esc(x.responsible||"-")}</td><td>${fmt(x.reviewDate)}</td><td>${esc(x.observations||"-")}</td></tr>`;}).join("")}</tbody></table><div class="report-signatures"><div>${esc(snapshot.work?.sstResponsible||"")}<br><b>RESPONSABLE SST</b></div><div>${esc(snapshot.work?.superintendent||"")}<br><b>SUPERINTENDENTE</b></div><div>${fmt(doc.date||today())}<br><b>FECHA</b></div></div>`;openSystemReport(html,{...doc,downloadName:"cumplimiento-normativo",code:"GVC-SSH-CUM-001",revision:"Rev. 01",work:snapshot.work});}

function recordsForWork(workId){try{return (JSON.parse(localStorage.getItem("gvc-extintores-records-v1"))||[]).filter(x=>(x.workId||"legacy")===workId);}catch{return [];}}
function buildAlerts(workId){const alerts=[],stats=complianceStats(workId),records=recordsForWork(workId),week=getWeekStart(today());stats.entries.forEach(x=>{if(x.status==="No cumple")alerts.push({level:x.percentage<=25?"Crítico":"Urgente",title:x.code,detail:x.observations||"Cumplimiento insuficiente"});else if(x.status==="Parcial")alerts.push({level:"Pendiente",title:x.code,detail:x.observations||"Acciones pendientes"});});if(!records.some(x=>x.type==="incident"&&x.date===today()))alerts.push({level:"Atención",title:"Reporte diario",detail:"Sin generar hoy"});if(!records.some(x=>x.type!=="incident"&&(x.date||"")>=week))alerts.push({level:"Pendiente",title:"Inspecciones",detail:"Sin inspecciones esta semana"});data.investigations.filter(x=>x.workId===workId&&x.dueDate&&x.dueDate<today()).forEach(x=>alerts.push({level:"Urgente",title:x.folio,detail:"Acción correctiva vencida"}));return alerts.sort((a,b)=>["Crítico","Urgente","Pendiente","Atención"].indexOf(a.level)-["Crítico","Urgente","Pendiente","Atención"].indexOf(b.level));}
function executiveIcon(index){const paths=["M4 20v-2a4 4 0 0 1 4-4h8a4 4 0 0 1 4 4v2 M12 11a4 4 0 1 0 0-8 4 4 0 0 0 0 8","M4 21V3h12v18 M8 7h4 M8 11h4 M8 15h4 M16 9h4v12","M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2 M9 11a4 4 0 1 0 0-8 4 4 0 0 0 0 8 M22 21v-2a4 4 0 0 0-3-3.87","M6 2h9l5 5v15H6z M14 2v6h6 M9 13h8 M9 17h8","M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10 M9 12l2 2 4-4","M12 9v4 M12 17h.01 M10.3 2.9 1.8 17a2 2 0 0 0 1.7 3h17a2 2 0 0 0 1.7-3L13.7 2.9a2 2 0 0 0-3.4 0","M12 9v4 M12 17h.01 M10.3 2.9 1.8 17a2 2 0 0 0 1.7 3h17a2 2 0 0 0 1.7-3L13.7 2.9a2 2 0 0 0-3.4 0"];return `<span class="executive-kpi-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="${paths[index]}"></path></svg></span>`;}
function executiveKpis(){const records=appRecords(),yesterday=lastDays(2)[0],todayPresent=presentCount(activeId,today()),yesterdayPresent=presentCount(activeId,yesterday),todayVisitors=visitors().filter(x=>x.date===today()).length,yesterdayVisitors=visitors().filter(x=>x.date===yesterday).length,dailyToday=records.filter(x=>x.type==="incident"&&x.date===today()).length,week=getWeekStart(today()),inspectionsWeek=records.filter(x=>x.type!=="incident"&&(x.date||"")>=week).length,values=[[todayPresent,"Trabajadores presentes",todayPresent-yesterdayPresent],[contractors().filter(x=>x.status==="Activo").length,"Contratistas activos",0],[todayVisitors,"Visitantes hoy",todayVisitors-yesterdayVisitors],[dailyToday,"Reportes diarios hoy",0],[inspectionsWeek,"Inspecciones esta semana",0],[investigations().length,"Accidentes registrados",0],[records.filter(x=>x.type==="incident"&&x.accidentOccurred!=="Sí").length,"Incidentes registrados",0]];return values;}
function recentActivities(workId){const rows=[],work=workById(workId);recordsForWork(workId).forEach(x=>rows.push({at:x.createdAt||`${x.date}T${x.startTime||x.time||"00:00"}`,activity:historyLabel(x.type),user:x.reportedBy||x.inspector||x.safetyName||"Usuario de obra",work:work?.name}));data.visitors.filter(x=>x.workId===workId).forEach(x=>rows.push({at:`${x.date}T${x.entry||"00:00"}`,activity:`Visitante registrado: ${x.name}`,user:x.visits||"Acceso",work:work?.name}));Object.keys(data.attendance).filter(key=>key.startsWith(workId+"|")&&Object.values(data.attendance[key]||{}).some(Boolean)).forEach(key=>rows.push({at:`${key.split("|")[1]}T07:00`,activity:"Registro de asistencia",user:"Responsable de obra",work:work?.name}));data.investigations.filter(x=>x.workId===workId).forEach(x=>rows.push({at:x.createdAt||`${x.date}T${x.time||"00:00"}`,activity:`Investigación ${x.folio}`,user:x.responsible||"Seguridad",work:work?.name}));data.activity.filter(x=>x.workId===workId).forEach(x=>rows.push({at:x.createdAt,activity:x.description,user:x.user,work:work?.name}));return rows.sort((a,b)=>(b.at||"").localeCompare(a.at||"")).slice(0,8);}
function incidentTrendSvg(){const records=appRecords().filter(x=>x.type==="incident"),weeks=Array.from({length:4},(_,i)=>{const end=new Date(today()+"T12:00");end.setDate(end.getDate()-(3-i)*7);const start=new Date(end);start.setDate(end.getDate()-6);const s=systemLocalDateISO(start),e=systemLocalDateISO(end),items=records.filter(x=>x.date>=s&&x.date<=e);return {incidents:items.filter(x=>x.accidentOccurred!=="Sí").length,accidents:items.filter(x=>x.accidentOccurred==="Sí").length};}),max=Math.max(1,...weeks.flatMap(x=>[x.incidents,x.accidents])),points=key=>weeks.map((x,i)=>`${20+i*70},${125-x[key]/max*100}`).join(" ");return `<svg class="incident-lines" viewBox="0 0 250 150" role="img" aria-label="Tendencia de incidentes y accidentes"><g stroke="#e5e9ed" stroke-width="1"><path d="M20 25H235M20 75H235M20 125H235"></path></g><polyline fill="none" stroke="#f28a19" stroke-width="3" points="${points("incidents")}"></polyline><polyline fill="none" stroke="#dc2b32" stroke-width="3" points="${points("accidents")}"></polyline>${weeks.map((x,i)=>`<text x="${20+i*70}" y="145" text-anchor="middle" font-size="9">Sem ${i+1}</text>`).join("")}</svg>`;}
function workforceSummary(workId){const previous=activeId;activeId=workId;try{const present=workers().filter(w=>data.attendance[attendanceKey(today())]?.[w.id]==="P"),total=present.length;return contractors().map(c=>({name:c.name,count:present.filter(w=>w.contractorId===c.id).length})).filter(x=>x.count).map(x=>({...x,percentage:total?Math.round(x.count/total*100):0}));}finally{activeId=previous;}}
function renderExecutiveDashboard(){const kpis=executiveKpis(),target=q("#dashboardKpis");target.innerHTML=kpis.map(([value,label,delta],i)=>`<article class="dashboard-kpi ${i>4?"alert":""}">${executiveIcon(i)}<b>${value}</b><span>${label}</span><div class="dashboard-trend">${delta>0?"↑ "+delta:delta<0?"↓ "+Math.abs(delta):"Sin cambios"}${delta?" vs ayer":""}</div></article>`).join("");const stats=complianceStats(activeId),alerts=buildAlerts(activeId),activities=recentActivities(activeId),force=workforceSummary(activeId),work=activeWork();q("#dashboardInsights").innerHTML=`<div class="dashboard-executive-grid"><article class="executive-card"><h2>Cumplimiento normativo general</h2><div class="compliance-ring" style="--score:${stats.general}%"><strong>${stats.general}%</strong></div><button class="back" data-dashboard-compliance>Ver detalle por NOM →</button></article><article class="executive-card"><h2>Cumplimiento por NOM</h2><div class="nom-mini-list">${stats.entries.map(x=>`<div class="nom-mini-row"><span>${x.code}</span><div class="nom-mini-track"><div class="nom-mini-fill ${complianceClass(x)}" style="width:${Number(x.percentage)||0}%"></div></div><b>${x.status==="No aplica"?"N/A":(Number(x.percentage)||0)+"%"}</b></div>`).join("")}</div></article><article class="executive-card"><h2>Tendencia de incidentes y accidentes</h2>${incidentTrendSvg()}</article><article class="executive-card"><h2>Alertas y pendientes</h2><div class="alert-list">${alerts.slice(0,5).map(x=>`<div class="alert-item ${x.level.toLowerCase().replace("í","i")}"><span class="alert-icon">!</span><div><b>${esc(x.title)}</b><small>${esc(x.detail)}</small></div><span class="alert-level">${x.level}</span></div>`).join("")||'<div class="empty-management">Sin alertas activas.</div>'}</div></article></div><div class="dashboard-lower-grid"><article class="executive-card"><h2>Actividad reciente</h2><table class="recent-activity-table"><thead><tr><th>Fecha</th><th>Actividad</th><th>Realizado por</th></tr></thead><tbody>${activities.slice(0,6).map(x=>`<tr><td>${fmt(x.at?.slice(0,10))}<br>${esc(x.at?.slice(11,16)||"")}</td><td>${esc(x.activity)}</td><td>${esc(x.user)}</td></tr>`).join("")||'<tr><td colspan="3">Sin actividad registrada.</td></tr>'}</tbody></table></article><article class="executive-card"><h2>Fuerza de trabajo por contratista</h2><div class="workforce-bars">${force.map(x=>`<div class="workforce-row"><span>${esc(x.name)}</span><div class="workforce-track"><div class="workforce-fill" style="width:${x.percentage}%"></div></div><b>${x.count} (${x.percentage}%)</b></div>`).join("")||'<div class="empty-management">Sin trabajadores presentes.</div>'}</div></article></div><div class="work-info-strip"><span><b>Obra actual</b>${esc(work.name)}</span><span><b>Ubicación</b>${esc(work.location)}</span><span><b>Inicio de obra</b>${fmt(work.startDate)||"Sin fecha"}</span><span><b>Responsable SST</b>${esc(work.sstResponsible||"Sin asignar")}</span></div>`;q("[data-dashboard-compliance]")?.addEventListener("click",openComplianceModule);}
renderDashboard=function(){phase2RenderDashboardFinal();renderExecutiveDashboard();markSidebar("dashboard");};

renderWorkforce=function(){const groups=workforceSummary(activeId),present=groups.reduce((s,x)=>s+x.count,0),vis=visitors().filter(v=>v.date===today()&&!v.exit).length;q("#managementContent").innerHTML=`<div class="kpi-grid"><div class="kpi-card"><b>${present}</b><span>Trabajadores presentes</span></div><div class="kpi-card"><b>${groups.length}</b><span>Contratistas con presencia</span></div><div class="kpi-card"><b>${vis}</b><span>Visitantes en obra</span></div><div class="kpi-card"><b>${present+vis}</b><span>Total en sitio</span></div></div><div class="data-panel"><h2>Accesos de fuerza de trabajo</h2><div class="management-actions inline-actions"><button class="secondary" data-workforce-jump="contractors">Contratistas</button><button class="secondary" data-workforce-jump="workers">Trabajadores</button><button class="secondary" data-workforce-jump="visitors">Visitantes</button><button class="secondary" data-workforce-jump="badges">Gafetes</button></div></div><div class="data-panel"><h2>Distribución por contratista</h2><div class="workforce-bars workforce-panel">${groups.map(x=>`<div class="workforce-row"><span>${esc(x.name)}</span><div class="workforce-track"><div class="workforce-fill" style="width:${x.percentage}%"></div></div><b>${x.count} (${x.percentage}%)</b></div>`).join("")||'<div class="empty-management">No hay asistencias marcadas hoy.</div>'}</div></div>`;qa("[data-workforce-jump]").forEach(button=>button.onclick=()=>{const target=button.dataset.workforceJump;if(target==="badges")openModule("workers");else openModule(target);});};

renderBadge=function(worker){worker.badgeIssuedDate||=today();phase2RenderBadgeFinal(worker);save();};
documentsAcrossWorks=function(){const docs=phase2DocumentsAcrossWorks();data.visitors.forEach(v=>{const work=workById(v.workId);docs.push({...v,type:"visitor",source:"virtual",workName:work?.name,development:work?.development});});data.workers.filter(w=>w.badgeFolio).forEach(w=>{const work=workById(w.workId);docs.push({id:`badge-${w.id}`,type:"badge",source:"virtual",workId:w.workId,workName:work?.name,development:work?.development,workerId:w.id,date:w.badgeIssuedDate||w.admissionDate||"",folio:w.badgeFolio});});return docs;};
documentContractor=function(doc){if(doc.type==="visitor")return doc.company||"";if(doc.type==="badge")return contractorNameForWork(doc.workId,data.workers.find(w=>w.id===doc.workerId)?.contractorId);return phase2DocumentContractor(doc);};
function contractorNameForWork(workId,id){return data.contractors.find(x=>x.workId===workId&&x.id===id)?.name||"";}
historyLabel=function(type){return ({compliance:"Cumplimiento normativo",visitor:"Registro de visitante",badge:"Gafete"}[type]||phase2HistoryLabel(type));};
openFilteredDocument=function(doc){if(doc.type==="compliance")return renderComplianceReport(doc);if(doc.type==="badge"){const previous=activeId;activeId=doc.workId;try{return renderBadge(data.workers.find(x=>x.id===doc.workerId));}finally{activeId=previous;}}if(doc.type==="visitor")return renderVisitorReport(doc);return phase2OpenFilteredDocument(doc);};
function renderVisitorReport(visitor){const work=workById(visitor.workId),html=`<div class="report-title"><div class="report-logo">GVC</div><div><b>GRAN VISIÓN CONSTRUCCIÓN</b><h1>REGISTRO DE VISITANTE</h1></div><div><b>${fmt(visitor.date)}</b><br>Rev. 01</div></div><div class="official-meta"><div><b>OBRA</b>${esc(work?.name)}</div><div><b>VISITANTE</b>${esc(visitor.name)}</div><div><b>EMPRESA</b>${esc(visitor.company)}</div><div><b>ENTRADA / SALIDA</b>${esc(visitor.entry)} / ${esc(visitor.exit||"En obra")}</div></div><div class="report-band">Datos de la visita</div><div class="incident-report-section"><div><b>MOTIVO</b>${esc(visitor.reason)}</div><div><b>PERSONA QUE VISITA</b>${esc(visitor.visits)}</div><div><b>OBSERVACIONES</b>${esc(visitor.notes||"Sin observaciones")}</div></div><div class="report-signatures"><div>${esc(visitor.name)}<br><b>VISITANTE</b></div><div>${esc(visitor.visits)}<br><b>PERSONA VISITADA</b></div><div>${fmt(visitor.date)}<br><b>FECHA</b></div></div>`;openSystemReport(html,{...visitor,downloadName:"registro-visitante",code:"GVC-SSH-VIS-001",revision:"Rev. 01",work});}

function bindPhase3Shell(){bindExecutiveNavigation();bindPhase3WorkForm();q("#managementBack").onclick=()=>{renderDashboard();displayView("homeView");};q("#homeButton").onclick=()=>{if(activeWork()){renderDashboard();displayView("homeView");}else{renderWorks();displayView("worksView");}};}
function bindComplianceDelegation(){q("#managementContent")?.addEventListener("click",event=>{if(event.target.id==="cancelCompliance")renderComplianceModule();});}
function normalized(value){return String(value||"").trim().toLocaleLowerCase("es-MX");}
function bindOperationalGuards(){document.addEventListener("submit",event=>{const form=event.target,f=new FormData(form);let duplicate=false,message="",field="";if(form.id==="workForm"){const editId=form.dataset.editId||"",number=normalized(f.get("workNumber")),name=normalized(f.get("name")),development=normalized(f.get("development"));duplicate=data.works.some(x=>x.id!==editId&&((number&&normalized(x.workNumber)===number)||(normalized(x.name)===name&&normalized(x.development)===development)));message="Ya existe una obra, activa o recuperable, con ese número o nombre.";field=number?"workNumber":"name";}else if(form.id==="contractorForm"){const editId=form.dataset.editId||"",name=normalized(f.get("name"));duplicate=data.contractors.some(x=>x.id!==editId&&x.workId===activeId&&normalized(x.name)===name);message="Este contratista ya está registrado en la obra.";field="name";}else if(form.id==="workerForm"){const editId=form.dataset.editId||"",nss=normalized(f.get("nss")),name=normalized(f.get("name")),contractorId=f.get("contractorId");duplicate=data.workers.some(x=>x.id!==editId&&x.workId===activeId&&((nss&&normalized(x.nss)===nss)||(normalized(x.name)===name&&x.contractorId===contractorId)));message="El trabajador ya está registrado en esta obra.";field=nss?"nss":"name";}if(!duplicate)return;event.preventDefault();event.stopImmediatePropagation();form.elements[field]?.focus();toast(message);},true);}
function bindSuccessMessages(){const messages={workForm:"Obra guardada correctamente.",contractorForm:"Contratista guardado correctamente.",workerForm:"Trabajador guardado correctamente.",visitorForm:"Visitante registrado correctamente.",investigationForm:"Investigación guardada correctamente."};document.addEventListener("submit",event=>{const message=messages[event.target.id];if(message)setTimeout(()=>toast(message),0);});}
function registerPhase4Extensions(){const registry=window.GvcExtensions;if(!registry)return;registry.registerModule({id:"compliance",label:"Cumplimiento NOM",slot:"work-menu",status:"active"});registry.registerModule({id:"compliance-matrix",label:"Matriz de cumplimiento",slot:"work-menu",status:"active"});registry.registerDocumentType({id:"compliance",slot:"document-history",status:"active"});}

// Phase 5: auditable operational criteria and automatic activity scheduling.
const nomCriteriaCatalog={
  "NOM-002-STPS":["Análisis y clasificación del riesgo de incendio","Extintores suficientes, visibles y vigentes","Equipos y redes contra incendio","Control de sustancias inflamables","Control de fuentes de ignición","Señalización de emergencia","Rutas y salidas de evacuación","Brigada contra incendio","Capacitación y constancias","Plan de atención a emergencias","Simulacros documentados","Orden y limpieza"],
  "NOM-004-STPS":["Inventario de maquinaria y equipo","Análisis de riesgos por equipo","Guardas y dispositivos de seguridad","Controles y paro de emergencia","Bloqueo de energías peligrosas","Programa de mantenimiento preventivo","Manuales y procedimientos de operación","Personal autorizado","Capacitación del operador","Inspecciones documentadas"],
  "NOM-009-STPS":["Procedimiento para trabajos en altura","Análisis de riesgos","Personal autorizado","Capacitación y autorización vigente","Sistemas personales anticaídas","Líneas de vida","Puntos de anclaje","Andamios y plataformas","Escaleras portátiles","Plan de rescate","Evidencia documental"],
  "NOM-010-STPS":["Reconocimiento de agentes químicos","Hojas de datos de seguridad","Evaluación y muestreo de exposición","Comparación con límites permisibles","Controles de ingeniería","Ventilación y extracción","Equipo de protección personal","Capacitación al personal","Vigilancia a la salud","Registros de evaluación"],
  "NOM-011-STPS":["Reconocimiento de fuentes de ruido","Evaluación de niveles de exposición","Comparación con límites máximos","Controles técnicos y administrativos","Programa de conservación auditiva","Protectores auditivos","Vigilancia médica","Capacitación","Señalización de áreas","Registros y estudios"],
  "NOM-017-STPS":["Análisis de riesgos por puesto","Selección de EPP","Matriz de EPP autorizada","Entrega documentada","Capacitación de uso","Limpieza y mantenimiento","Reposición y disposición","Supervisión de uso","Compatibilidad entre equipos","Registros de entrega"],
  "NOM-019-STPS":["Acta constitutiva de la comisión","Integración y vigencia de miembros","Programa anual de recorridos","Recorridos de verificación","Actas y hallazgos","Investigación de accidentes","Capacitación de integrantes","Seguimiento de medidas","Evidencias de cierre","Informe anual"],
  "NOM-024-STPS":["Reconocimiento de fuentes de vibración","Evaluación de exposición","Comparación con límites","Controles técnicos","Programa de mantenimiento","Equipo de protección","Vigilancia médica","Capacitación","Señalización y acceso","Registros de evaluación"],
  "NOM-025-STPS":["Reconocimiento de áreas y tareas","Estudio de niveles de iluminación","Cumplimiento de niveles mínimos","Iluminación de emergencia","Mantenimiento de luminarias","Control de deslumbramiento","Contraste adecuado","Reportes de evaluación","Acciones correctivas"],
  "NOM-026-STPS":["Inventario de señales necesarias","Colores de seguridad","Señales de prohibición y obligación","Identificación de tuberías","Señales de emergencia","Ubicación y visibilidad","Conservación y mantenimiento","Capacitación sobre señalización","Planos y rutas actualizados"],
  "NOM-029-STPS":["Procedimientos de mantenimiento eléctrico","Diagramas y planos actualizados","Personal autorizado y capacitado","Desenergización segura","Bloqueo y etiquetado","Equipo de protección dieléctrico","Herramientas aisladas","Puesta a tierra","Permisos de trabajo","Delimitación y señalización","Inspecciones eléctricas","Plan de atención a emergencias"],
  "NOM-030-STPS":["Diagnóstico de seguridad y salud","Programa de seguridad y salud","Responsable de servicios preventivos","Recorridos y verificaciones","Vigilancia a la salud","Capacitación preventiva","Registros y evidencias","Acciones preventivas y correctivas","Seguimiento de compromisos","Evaluación anual del programa"],
  "NOM-031-STPS":["Análisis de riesgos de la obra","Sistema de seguridad y salud","Control de accesos","Excavaciones y zanjas","Trabajos en altura","Maquinaria y equipo","Instalaciones eléctricas provisionales","Equipo de protección personal","Señalización y delimitación","Plan de emergencias","Control de contratistas","Inspecciones de seguridad","Registros documentales"]
};
const phase4ComplianceStats=complianceStats,phase4BuildAlerts=buildAlerts,phase4RecentActivities=recentActivities,phase4OpenFilteredDocumentFinal=openFilteredDocument,phase4HistoryLabelFinal=historyLabel;

function criterionId(code,index){return `${code.replace(/[^0-9]/g,"")}-${String(index+1).padStart(2,"0")}`;}
function ensureOperationalCriteria(workId,code){const entry=ensureCompliance(workId).find(x=>x.code===code);entry.criteria||=nomCriteriaCatalog[code].map((label,index)=>({id:criterionId(code,index),label,status:"No aplica",reviewDate:"",responsible:"",evidence:[],observations:"",pendingAction:"",commitmentDate:"",updatedAt:""}));return entry.criteria;}
function operationalEntryStats(entry){if(!entry.operationalAligned)return {percentage:Number(entry.percentage)||0,status:entry.status,counts:null};const counts={"Cumple":0,"Parcial":0,"No cumple":0,"No aplica":0};entry.criteria.forEach(x=>counts[x.status]=(counts[x.status]||0)+1);const applicable=counts.Cumple+counts.Parcial+counts["No cumple"],percentage=applicable?Math.round((counts.Cumple+counts.Parcial*.5)/applicable*100):0,status=!applicable?"No aplica":counts["No cumple"]||counts.Parcial?"Parcial":"Cumple";return {percentage,status,counts};}
function refreshOperationalEntry(entry){const stats=operationalEntryStats({...entry,operationalAligned:true});entry.operationalAligned=true;entry.percentage=stats.percentage;entry.status=stats.status;entry.operationalCounts=stats.counts;entry.updatedAt=new Date().toISOString();return stats;}
function migratePhase5Data(){data.schemaVersion=Math.max(Number(data.schemaVersion)||1,6);data.complianceAudit||=[];data.scheduledActivities||=[];data.works.forEach(work=>nomDefinitions.forEach(([code])=>ensureOperationalCriteria(work.id,code)));save();}

complianceStats=function(workId){const base=phase4ComplianceStats(workId),entries=base.entries.map(entry=>{const stats=operationalEntryStats(entry);return {...entry,percentage:stats.percentage,status:stats.status,operationalCounts:stats.counts};}),applicable=entries.filter(x=>x.status!=="No aplica"),weights=applicable.map(x=>({value:x.percentage,weight:x.operationalAligned?Math.max(1,x.criteria.filter(c=>c.status!=="No aplica").length):1})),totalWeight=weights.reduce((sum,x)=>sum+x.weight,0),general=totalWeight?Math.round(weights.reduce((sum,x)=>sum+x.value*x.weight,0)/totalWeight):0,counts={"Cumple":0,"Parcial":0,"No cumple":0,"No aplica":0};entries.forEach(x=>counts[x.status]=(counts[x.status]||0)+1);return {entries,applicable,general,risk:[...applicable].sort((a,b)=>a.percentage-b.percentage)[0]||null,pending:entries.filter(x=>x.status==="Parcial"||x.status==="No cumple").length,counts};};

openComplianceModule=function(){q("#managementTitle").textContent="Cumplimiento normativo";q("#managementSubtitle").textContent="Criterios verificables, evidencia y trazabilidad";q("#managementActions").innerHTML='<button class="secondary" id="scheduleActivities">Programación</button><button class="secondary" id="openMatrixFromCompliance">Matriz</button><button class="secondary" id="monthlyCompliance">Reporte mensual</button><button class="secondary" id="compliancePdf">Reporte general</button>';q("#scheduleActivities").onclick=()=>renderScheduleModule();q("#openMatrixFromCompliance").onclick=()=>openMatrixCompatibility();q("#monthlyCompliance").onclick=()=>createMonthlyComplianceDocument(activeId,currentMonthKey(),true);q("#compliancePdf").onclick=()=>createComplianceDocument();renderComplianceModule();displayView("managementView");markSidebar("compliance");};
renderComplianceModule=function(){const stats=complianceStats(activeId);q("#managementContent").innerHTML=`<div class="compliance-overview"><div class="compliance-score-card"><span>CUMPLIMIENTO GENERAL</span><strong>${stats.general}%</strong><span>${stats.applicable.length} NOM aplicables · ${stats.pending} con pendientes</span></div><div class="nom-management-grid">${stats.entries.map(entry=>`<article class="nom-card"><div class="nom-card-head"><h3>${entry.code}</h3><span class="nom-status">${esc(entry.status)}</span></div><p>${esc(entry.title)}</p><div class="nom-progress"><span class="${complianceClass(entry)}" style="width:${entry.percentage}%"></span></div><small>${entry.percentage}% · ${entry.criteria.length} criterios operativos</small><button class="secondary" data-open-criteria="${entry.code}">Administrar criterios</button></article>`).join("")}</div></div>`;qa("[data-open-criteria]").forEach(button=>button.onclick=()=>renderNomCriteria(button.dataset.openCriteria));};
function renderNomCriteria(code,editId=""){const entry=ensureCompliance(activeId).find(x=>x.code===code),criteria=ensureOperationalCriteria(activeId,code),stats=operationalEntryStats(entry),edit=criteria.find(x=>x.id===editId),audit=data.complianceAudit.filter(x=>x.workId===activeId&&x.nomCode===code).slice(0,20);q("#managementContent").innerHTML=`<div class="criteria-toolbar"><button class="back" id="criteriaBack">← Todas las NOM</button><div><h2>${entry.officialCode||entry.code}</h2><p>${esc(entry.title)} · ${stats.percentage}%</p></div></div>${edit?criterionForm(entry,edit):""}<div class="criteria-grid">${criteria.map(item=>`<article class="criterion-card status-${item.status.toLowerCase().replaceAll(" ","-")}"><div><span class="criterion-status">${esc(item.status)}</span><small>${fmt(item.reviewDate)||"Sin revisión"}</small></div><h3>${esc(item.label)}</h3><p>${esc(item.observations||"Sin observaciones")}</p><small>${esc(item.responsible||"Sin responsable")}</small><button class="secondary" data-edit-criterion="${item.id}">Revisar criterio</button></article>`).join("")}</div><section class="audit-panel"><h2>Historial de cumplimiento</h2>${audit.length?audit.map(a=>`<article class="audit-item"><time>${fmt(a.at.slice(0,10))} · ${a.at.slice(11,16)}</time><div><b>${esc(a.criterionLabel)}</b><span>${esc(a.previousStatus)} → ${esc(a.newStatus)}</span><p>${esc(a.comments||"Sin comentarios")}</p><small>${esc(a.user)}</small>${a.evidence?.length?`<div class="audit-evidence">${a.evidence.map(src=>`<img src="${src}" alt="Evidencia histórica">`).join("")}</div>`:""}</div></article>`).join(""):'<div class="empty-management">Aún no hay cambios registrados para esta NOM.</div>'}</section>`;q("#criteriaBack").onclick=renderComplianceModule;qa("[data-edit-criterion]").forEach(button=>button.onclick=()=>renderNomCriteria(code,button.dataset.editCriterion));q("#criterionForm")?.addEventListener("submit",saveCriterionReview);q("#cancelCriterion")?.addEventListener("click",()=>renderNomCriteria(code));}
function criterionForm(entry,item){return `<form id="criterionForm" class="modal-form criterion-form"><div class="section-title"><span>CR</span><div><h2>${esc(item.label)}</h2><p>${entry.code} · Registro auditable</p></div></div><input type="hidden" name="nomCode" value="${entry.code}"><input type="hidden" name="criterionId" value="${item.id}"><div class="field-grid"><label>Estado<select name="status" required>${["Cumple","Parcial","No cumple","No aplica"].map(value=>`<option ${item.status===value?"selected":""}>${value}</option>`).join("")}</select></label><label>Fecha de revisión<input name="reviewDate" type="date" value="${item.reviewDate||today()}" required></label><label class="wide">Responsable<input name="responsible" value="${esc(item.responsible)}" required></label><label class="wide">Observaciones<textarea name="observations" rows="3" required>${esc(item.observations)}</textarea></label><label class="wide">Acción pendiente<input name="pendingAction" value="${esc(item.pendingAction)}" placeholder="Medida correctiva o seguimiento"></label><label>Fecha compromiso<input name="commitmentDate" type="date" value="${item.commitmentDate||""}"></label><label class="wide">Evidencia<input name="evidence" type="file" accept="image/*" multiple></label><label class="wide">Comentario del cambio<textarea name="changeComment" rows="2" required placeholder="Motivo o resultado de la revisión"></textarea></label></div><div class="form-footer"><button class="ghost" id="cancelCriterion" type="button">Cancelar</button><button class="primary">Guardar revisión</button></div></form>`;}
function localDateTimeISO(){const now=new Date();return `${systemLocalDateISO(now)}T${now.toTimeString().slice(0,8)}`;}
async function saveCriterionReview(event){event.preventDefault();const form=event.currentTarget,f=new FormData(form),entry=ensureCompliance(activeId).find(x=>x.code===f.get("nomCode")),item=entry.criteria.find(x=>x.id===f.get("criterionId")),previousStatus=item.status,newEvidence=[];for(const file of [...form.elements.evidence.files].slice(0,4))newEvidence.push(await resizeImage(file));Object.assign(item,{status:f.get("status"),reviewDate:f.get("reviewDate"),responsible:f.get("responsible"),observations:f.get("observations"),pendingAction:f.get("pendingAction"),commitmentDate:f.get("commitmentDate"),evidence:[...(item.evidence||[]),...newEvidence].slice(-8),updatedAt:localDateTimeISO()});refreshOperationalEntry(entry);data.complianceAudit.unshift({id:uid(),workId:activeId,nomCode:entry.code,criterionId:item.id,criterionLabel:item.label,at:localDateTimeISO(),user:"Administrador GRAVI",previousStatus,newStatus:item.status,comments:f.get("changeComment"),evidence:newEvidence,snapshot:{status:item.status,reviewDate:item.reviewDate,responsible:item.responsible,observations:item.observations,pendingAction:item.pendingAction,commitmentDate:item.commitmentDate}});recordActivity("compliance",`${entry.code} · ${item.label}: ${previousStatus} → ${item.status}`);save();renderNomCriteria(entry.code);toast("Revisión guardada con trazabilidad histórica.");}

function currentMonthKey(){return today().slice(0,7);}
function shiftMonth(month,offset){const [year,value]=month.split("-").map(Number),date=new Date(year,value-1+offset,1);return `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,"0")}`;}
function firstWorkingDay(month){const [year,value]=month.split("-").map(Number),date=new Date(year,value-1,1,12);if(date.getDay()===0)date.setDate(2);return systemLocalDateISO(date);}
function workingDaysBetween(startExclusive,endInclusive){if(!startExclusive||!endInclusive||endInclusive<=startExclusive)return 0;let count=0,date=new Date(startExclusive+"T12:00");const end=new Date(endInclusive+"T12:00");while(date<end){date.setDate(date.getDate()+1);if(date.getDay()!==0)count++;}return count;}
function scheduledActivityState(task,asOf=today()){const comparison=task.executedDate||asOf,lateDays=workingDaysBetween(task.scheduledDate,comparison);if(task.executedDate)return {status:lateDays?"Vencida":"En tiempo",lateDays,completed:true};if(asOf>task.scheduledDate&&lateDays)return {status:"Vencida",lateDays,completed:false};const until=workingDaysBetween(asOf,task.scheduledDate);return {status:until<=3?"Próxima a vencer":"Programada",lateDays:0,completed:false};}
function ensureSchedulesForMonth(workId,month){[["firstAid","Inspección de botiquines"],["extinguisher","Inspección de extintores"]].forEach(([inspectionType,title])=>{const key=`${workId}|${month}|${inspectionType}`;if(!data.scheduledActivities.some(x=>x.key===key))data.scheduledActivities.push({id:uid(),key,workId,month,inspectionType,title,scheduledDate:firstWorkingDay(month),executedDate:"",recordId:"",createdAt:localDateTimeISO()});});}
function ensureMonthlySchedules(){const months=[shiftMonth(currentMonthKey(),-1),currentMonthKey(),shiftMonth(currentMonthKey(),1)],works=typeof navigableWorks52==="function"?navigableWorks52():data.works.filter(work=>!work.deletedAt);works.forEach(work=>months.forEach(month=>ensureSchedulesForMonth(work.id,month)));reconcileScheduledActivities();save();}
function reconcileScheduledActivities(){const records=JSON.parse(localStorage.getItem("gvc-extintores-records-v1")||"[]").filter(x=>x.status==="Finalizada"&&(x.type==="firstAid"||x.type==="extinguisher")).sort((a,b)=>(a.date||a.createdAt||"").localeCompare(b.date||b.createdAt||""));records.forEach(record=>{const date=record.date||record.createdAt?.slice(0,10),month=date?.slice(0,7),task=data.scheduledActivities.find(x=>x.workId===(record.workId||"legacy")&&x.month===month&&x.inspectionType===record.type&&!x.recordId);if(task){task.recordId=record.id;task.executedDate=date;task.updatedAt=new Date().toISOString();}});}
function renderScheduleModule(month=currentMonthKey()){ensureSchedulesForMonth(activeId,month);reconcileScheduledActivities();save();const tasks=data.scheduledActivities.filter(x=>x.workId===activeId&&x.month===month),rows=tasks.map(task=>{const state=scheduledActivityState(task);return `<tr><td>${esc(task.title)}</td><td>${fmt(task.scheduledDate)}</td><td>${fmt(task.executedDate)||"Pendiente"}</td><td><span class="activity-state ${state.status.toLowerCase().replaceAll(" ","-")}">${state.status}</span></td><td>${state.lateDays}</td></tr>`;}).join("");q("#managementContent").innerHTML=`<section class="schedule-panel"><div class="schedule-header"><div><h2>Programación automática</h2><p>Primer día laborable del mes. Los domingos se trasladan al día siguiente.</p></div><label>Mes<input id="scheduleMonth" type="month" value="${month}"></label></div><table class="data-table"><thead><tr><th>Actividad</th><th>Programada</th><th>Ejecución</th><th>Estado</th><th>Días de atraso</th></tr></thead><tbody>${rows||'<tr><td colspan="5">Sin actividades programadas.</td></tr>'}</tbody></table><div class="form-footer"><button class="ghost" id="scheduleBack">Volver a cumplimiento</button><button class="primary" id="scheduleMonthlyReport">Generar reporte mensual</button></div></section>`;q("#scheduleMonth").onchange=e=>renderScheduleModule(e.target.value);q("#scheduleBack").onclick=renderComplianceModule;q("#scheduleMonthlyReport").onclick=()=>createMonthlyComplianceDocument(activeId,month,true);}

function criterionSnapshotAt(workId,code,item,monthEnd){const audit=data.complianceAudit.filter(x=>x.workId===workId&&x.nomCode===code&&x.criterionId===item.id&&x.at.slice(0,10)<=monthEnd).sort((a,b)=>b.at.localeCompare(a.at))[0];if(audit)return {...item,...audit.snapshot,status:audit.newStatus};if(item.reviewDate&&item.reviewDate<=monthEnd)return {...item};return {...item,status:"No aplica",observations:"",pendingAction:"",commitmentDate:""};}
function criterionStatusAt(workId,code,item,monthEnd){return criterionSnapshotAt(workId,code,item,monthEnd).status;}
function monthEndDate(month){const [year,value]=month.split("-").map(Number);return systemLocalDateISO(new Date(year,value,0,12));}
function monthlyComplianceStats(workId,month){const end=monthEndDate(month),criteria=ensureCompliance(workId).flatMap(entry=>ensureOperationalCriteria(workId,entry.code).map(item=>({...criterionSnapshotAt(workId,entry.code,item,end),nomCode:entry.code}))),nomEntries=ensureCompliance(workId).map(entry=>{const statuses=criteria.filter(x=>x.nomCode===entry.code).map(x=>x.status),counts={"Cumple":0,"Parcial":0,"No cumple":0,"No aplica":0};statuses.forEach(status=>counts[status]++);const applicable=counts.Cumple+counts.Parcial+counts["No cumple"],percentage=applicable?Math.round((counts.Cumple+counts.Parcial*.5)/applicable*100):0;return {code:entry.code,title:entry.title,percentage,counts};}),totals={"Cumple":0,"Parcial":0,"No cumple":0,"No aplica":0};nomEntries.forEach(entry=>Object.keys(totals).forEach(key=>totals[key]+=entry.counts[key]));const applicable=totals.Cumple+totals.Parcial+totals["No cumple"],general=applicable?Math.round((totals.Cumple+totals.Parcial*.5)/applicable*100):0,findings=criteria.filter(x=>x.status==="Parcial"||x.status==="No cumple"),overdue=findings.filter(x=>x.commitmentDate&&x.commitmentDate<end),tasks=data.scheduledActivities.filter(x=>x.workId===workId&&x.month===month).map(task=>({...task,state:scheduledActivityState(task,end)}));return {month,end,general,nomEntries,totals,findings,overdue,tasks};}
function nextMonthlyComplianceFolio(month){const year=month.slice(0,4),count=data.histories.filter(x=>x.type==="monthlyCompliance"&&(x.folio||"").startsWith(`CMC-${year}`)).length+1;return `CMC-${year}-${String(count).padStart(4,"0")}`;}
function createMonthlyComplianceDocument(workId,month,open=false,automatic=false){ensureMonthlySchedules();const current=monthlyComplianceStats(workId,month),previous=monthlyComplianceStats(workId,shiftMonth(month,-1)),doc={id:uid(),workId,type:"monthlyCompliance",date:current.end,month,folio:nextMonthlyComplianceFolio(month),createdAt:new Date().toISOString(),automatic,monthlySnapshot:{work:{...workById(workId)},current,previous,variation:current.general-previous.general}};data.histories.push(doc);recordActivity("compliance",`Reporte mensual ${month} generado`,workId);save();if(open)renderMonthlyComplianceReport(doc);return doc;}
function ensureAutomaticMonthlyReports(){const previous=shiftMonth(currentMonthKey(),-1),works=typeof navigableWorks52==="function"?navigableWorks52():data.works.filter(work=>!work.deletedAt);works.forEach(work=>{if(!data.histories.some(x=>x.workId===work.id&&x.type==="monthlyCompliance"&&x.month===previous&&x.automatic))createMonthlyComplianceDocument(work.id,previous,false,true);});}
function renderMonthlyComplianceReport(doc){const snap=doc.monthlySnapshot,current=snap.current,previous=snap.previous,variation=snap.variation,html=`<div class="report-title"><div class="report-logo">GVC</div><div><b>GRAN VISIÓN CONSTRUCCIÓN</b><h1>REPORTE MENSUAL DE CUMPLIMIENTO</h1></div><div><b>${esc(doc.folio)}</b><br>${esc(doc.month)} · Rev. 01</div></div><div class="official-meta"><div><b>OBRA</b>${esc(snap.work.name)}</div><div><b>CUMPLIMIENTO ACTUAL</b>${current.general}%</div><div><b>MES ANTERIOR</b>${previous.general}%</div><div><b>VARIACIÓN</b>${variation>0?"+":""}${variation} puntos · ${variation>0?"Ascendente":variation<0?"Descendente":"Sin cambio"}</div></div><div class="report-band">Cumplimiento por NOM</div><table class="report-table"><thead><tr><th>NOM</th><th>%</th><th>Cumple</th><th>Parcial</th><th>No cumple</th><th>N/A</th></tr></thead><tbody>${current.nomEntries.map(x=>`<tr><td>${x.code}</td><td>${x.percentage}%</td><td>${x.counts.Cumple}</td><td>${x.counts.Parcial}</td><td>${x.counts["No cumple"]}</td><td>${x.counts["No aplica"]}</td></tr>`).join("")}</tbody></table><div class="report-band">Hallazgos y acciones pendientes</div><table class="report-table"><thead><tr><th>NOM</th><th>Criterio</th><th>Estado</th><th>Hallazgo</th><th>Acción / compromiso</th></tr></thead><tbody>${current.findings.map(x=>`<tr><td>${x.nomCode}</td><td>${esc(x.label)}</td><td>${esc(x.status)}</td><td>${esc(x.observations||"-")}</td><td>${esc(x.pendingAction||"-")} · ${fmt(x.commitmentDate)}</td></tr>`).join("")||'<tr><td colspan="5">Sin hallazgos abiertos.</td></tr>'}</tbody></table><div class="report-band">Inspecciones mensuales</div><table class="report-table"><thead><tr><th>Actividad</th><th>Programada</th><th>Ejecución</th><th>Estado</th><th>Atraso</th></tr></thead><tbody>${current.tasks.map(x=>`<tr><td>${esc(x.title)}</td><td>${fmt(x.scheduledDate)}</td><td>${fmt(x.executedDate)||"Pendiente"}</td><td>${x.state.status}</td><td>${x.state.lateDays} días</td></tr>`).join("")||'<tr><td colspan="5">Sin actividades del mes.</td></tr>'}</tbody></table><div class="report-notes"><b>Resumen:</b> ${current.totals.Cumple} criterios cumplidos, ${current.totals.Parcial} parciales, ${current.totals["No cumple"]} no cumplidos y ${current.overdue.length} acciones vencidas.</div><div class="report-signatures"><div>${esc(snap.work.sstResponsible||"")}<br><b>RESPONSABLE SST</b></div><div>${esc(snap.work.superintendent||"")}<br><b>SUPERINTENDENTE</b></div><div>${fmt(doc.date)}<br><b>FECHA</b></div></div>`;openSystemReport(html,{...doc,downloadName:`cumplimiento-mensual-${doc.month}`,code:"GVC-SSH-CUM-M01",revision:"Rev. 01",work:snap.work});}

renderComplianceReport=function(doc){const snapshot=doc.complianceSnapshot||{work:workById(doc.workId),entries:complianceStats(doc.workId).entries,stats:complianceStats(doc.workId)},entries=snapshot.entries,html=`<div class="report-title"><div class="report-logo">GVC</div><div><b>GRAN VISIÓN CONSTRUCCIÓN</b><h1>REPORTE DE CUMPLIMIENTO NORMATIVO</h1></div><div><b>${esc(doc.folio||"BORRADOR")}</b><br>Rev. 02</div></div><div class="official-meta"><div><b>OBRA</b>${esc(snapshot.work?.name)}</div><div><b>UBICACIÓN</b>${esc(snapshot.work?.location)}</div><div><b>RESPONSABLE SST</b>${esc(snapshot.work?.sstResponsible||"-")}</div><div><b>CUMPLIMIENTO GENERAL</b>${snapshot.stats.general}%</div></div><div class="report-band">Criterios operativos por NOM</div><table class="report-table compliance-report-table"><thead><tr><th>NOM</th><th>Estado</th><th>%</th><th>Cumple</th><th>Parcial</th><th>No cumple</th><th>N/A</th></tr></thead><tbody>${entries.map(entry=>{const criteria=entry.criteria||[],counts={"Cumple":0,"Parcial":0,"No cumple":0,"No aplica":0};criteria.forEach(item=>counts[item.status]=(counts[item.status]||0)+1);return `<tr><td>${esc(entry.officialCode||entry.code)}</td><td>${esc(entry.status)}</td><td>${Number(entry.percentage)||0}%</td><td>${counts.Cumple}</td><td>${counts.Parcial}</td><td>${counts["No cumple"]}</td><td>${counts["No aplica"]}</td></tr>`;}).join("")}</tbody></table><div class="report-band">Hallazgos y acciones pendientes</div><table class="report-table"><thead><tr><th>NOM</th><th>Criterio</th><th>Estado</th><th>Hallazgo</th><th>Acción</th></tr></thead><tbody>${entries.flatMap(entry=>(entry.criteria||[]).filter(item=>item.status==="Parcial"||item.status==="No cumple").map(item=>`<tr><td>${entry.code}</td><td>${esc(item.label)}</td><td>${esc(item.status)}</td><td>${esc(item.observations||"-")}</td><td>${esc(item.pendingAction||"-")} · ${fmt(item.commitmentDate)}</td></tr>`)).join("")||'<tr><td colspan="5">Sin hallazgos abiertos.</td></tr>'}</tbody></table><div class="report-signatures"><div>${esc(snapshot.work?.sstResponsible||"")}<br><b>RESPONSABLE SST</b></div><div>${esc(snapshot.work?.superintendent||"")}<br><b>SUPERINTENDENTE</b></div><div>${fmt(doc.date||today())}<br><b>FECHA</b></div></div>`;openSystemReport(html,{...doc,downloadName:"cumplimiento-normativo",code:"GVC-SSH-CUM-001",revision:"Rev. 02",work:snapshot.work});};

buildAlerts=function(workId){const alerts=phase4BuildAlerts(workId),tasks=data.scheduledActivities.filter(x=>x.workId===workId&&(x.month===currentMonthKey()||x.month===shiftMonth(currentMonthKey(),1)));tasks.forEach(task=>{const state=scheduledActivityState(task);if(state.status==="Vencida"&&!state.completed)alerts.push({level:"Urgente",title:task.title,detail:`${state.lateDays} días de atraso · programada ${fmt(task.scheduledDate)}`});else if(state.status==="Próxima a vencer"&&!state.completed)alerts.push({level:"Pendiente",title:task.title,detail:`Programada ${fmt(task.scheduledDate)}`});});return alerts.sort((a,b)=>["Crítico","Urgente","Pendiente","Atención"].indexOf(a.level)-["Crítico","Urgente","Pendiente","Atención"].indexOf(b.level));};
recentActivities=function(workId){const rows=phase4RecentActivities(workId),completed=data.scheduledActivities.filter(x=>x.workId===workId&&x.executedDate).map(x=>({at:`${x.executedDate}T12:00`,activity:`${x.title} ejecutada`,user:"Programación automática",work:workById(workId)?.name}));return [...rows,...completed].sort((a,b)=>(b.at||"").localeCompare(a.at||"")).slice(0,8);};
historyLabel=function(type){return type==="monthlyCompliance"?"Cumplimiento mensual":phase4HistoryLabelFinal(type);};
