  const apply=()=>{qa(adminSelector).forEach(element=>element.classList.toggle("permission-hidden",!window.GraviSupabase.can("admin-write")));qa(fieldSelector).forEach(element=>element.classList.toggle("permission-hidden",!window.GraviSupabase.can("field-write")));};
